# A 4-step pipeline. ONE step has a single bug.
# Don't rewrite everything — bisect: print the value AFTER each step,
# find the step where it first goes wrong, and fix only that step.

def step1_parse(raw):
    # Correct: "3,1,2" -> [3, 1, 2]
    return [int(x) for x in raw.split(",")]

def step2_double(nums):
    # Should DOUBLE each number: [3, 1, 2] -> [6, 2, 4]
    return [n * 3 for n in nums]   # BUG: multiplies by 3, not 2

def step3_sort(nums):
    # Correct: [6, 2, 4] -> [2, 4, 6]
    return sorted(nums)

def step4_join(nums):
    # Correct: [2, 4, 6] -> "2-4-6"
    return "-".join(str(n) for n in nums)

def pipeline(raw):
    a = step1_parse(raw)
    b = step2_double(a)
    c = step3_sort(b)
    return step4_join(c)

print(pipeline("3,1,2"))
